class Solution {
public:
    vector<int> findAllPeople(int n, vector<vector<int>>& meetings, int firstPerson) {
        vector<vector<pair<int, int>>> graph(n);
        for (auto& meeting : meetings) {
            int x = meeting[0], y = meeting[1], time = meeting[2];
            graph[x].emplace_back(y, time);
            graph[y].emplace_back(x, time);
        }

        vector<bool> knows_secret(n, false);
        knows_secret[0] = true;
        knows_secret[firstPerson] = true;

        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
        pq.emplace(0, 0);
        pq.emplace(0, firstPerson);

        while (!pq.empty()) {
            auto [time, person] = pq.top();
            pq.pop();

            for (auto& [neighbor, meeting_time] : graph[person]) {
                if (meeting_time >= time && !knows_secret[neighbor]) {
                    knows_secret[neighbor] = true;
                    pq.emplace(meeting_time, neighbor);
                }
            }
        }

        vector<int> result;
        for (int i = 0; i < n; ++i) {
            if (knows_secret[i]) {
                result.push_back(i);
            }
        }
        return result;
    }
};
